-- ----------------------------
-- Table structure for apex_api_asset
-- ----------------------------
DROP TABLE IF EXISTS `apex_api_asset`;
CREATE TABLE `apex_api_asset` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `tenant_id` bigint NOT NULL COMMENT '租户ID',
  `name` varchar(128) NOT NULL COMMENT '资产名称',
  `description` varchar(512) DEFAULT NULL COMMENT '资产描述',
  `group_name` varchar(64) DEFAULT NULL COMMENT '分组名称',
  `protocol_type` varchar(32) NOT NULL COMMENT '协议类型 (HTTP/HTTPS)',
  `status` varchar(32) NOT NULL COMMENT '状态 (DRAFT/PUBLISHED/DEPRECATED/OFFLINE)',
  `base_path` varchar(256) DEFAULT NULL COMMENT '基础路径',
  `creator` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updater` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '更新者',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='API 资产主表';

